function [ttlL,ttlI,ttlP,lblP] = fLabelPhosV02(nmb)%% function label for magspec analysis %% [ttlL,ttlE,ttlA,ttlP,lbl] = fLabelMgspcV02()% gives you labels%% ttlL: title for log text output% ttlI: title for integrated text output% ttlP: title for image plot% lblP: lable for image plot%% Function Label for phos screen, ver.1% Kei Nakamura% Created on Friday, December 3rd 2010.% Modified on %% ver.1: %% main bocy%% label for log txt outputttlL{1} = 'scan';ttlL{2} = 'shot';ttlL{3} = ['ph',num2str(nmb),' img exist'];ttlL{4} = ['ph',num2str(nmb),' charge [pC]'];ttlL{5} = ['ph',num2str(nmb),' filter'];ttlL{6} = ['ph',num2str(nmb),' mean x [mm]'];ttlL{7} = ['ph',num2str(nmb),' mean y [mm]'];ttlL{8} = ['ph',num2str(nmb),' peak x [mm]'];ttlL{9} = ['ph',num2str(nmb),' peak y [mm]'];ttlL{10} = ['ph',num2str(nmb),' rms x [mm]'];ttlL{11} = ['ph',num2str(nmb),' rms y [mm]'];ttlL{12} = ['ph',num2str(nmb),' fwhm x [mm]'];ttlL{13} = ['ph',num2str(nmb),' fwhm y [mm]'];ttlL{14} = ['ph',num2str(nmb),' nmb saturated pixels'];ttlL{15} = 'env-bg [pC]';ttlL{16} = 'beam size [pixel]';ttlL{17} = 'size based bias [pC]';ttlL{18} = 'sn ratio';%% label for energy txt outputttlI{1} = 'x_mm';ttlI{2} = 'Charge_pC';ttlI{3} = 'y_mm';ttlI{4} = 'Charge_pC/';%% title for plotttlP{1} = 'log scale raw image';%% label for plotlblP{1} = 'pixel';lblP{2} = 'mm';
